            if search_in_structure(data, string):
                result.append(str(file_path))

        except (json.JSONDecodeError, IOError, OSError):
            continue

    return result

def search_in_structure(obj, target):
    if isinstance(obj, dict):
        for value in obj.values():
            if search_in_structure(value, target):
                return True
    elif isinstance(obj, list):
        for item in obj:
            if search_in_structure(item, target):
                return True
    elif isinstance(obj, str):
        if obj == target:
