    # Set random seed for reproducibility
    np.random.seed(random_seed)

    # Generate random sales and profit data
    sales_data = np.random.uniform(sales_lower, sales_upper, n_samples)
    profit_margin_data = np.random.uniform(profit_margin_min, profit_margin_max, n_samples)
